c(z.date().refine((d) => {
    const now = new Date();
    const minDate = new Date(now);
    minDate.setFullYear(minDate.getFullYear() - 1000);
    const maxDate = new Date(now);
    maxDate.setFullYear(maxDate.getFullYear() + 1000);
    return d >= minDate && d <= maxDate;
  }))
